@page "/categories"
@page "/categories/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(CategoryName is not null ? $"{CategoryName} Recipes" : "All Categories") - RecipeShare</PageTitle>

@if (CategoryName is null)
{
    <h1>Recipe Categories</h1>
    <div class="list-group">
        @foreach (var category in RecipeService.GetCategories())
        {
            <a href="categories/@category" class="list-group-item list-group-item-action">
                @category
            </a>
        }
    </div>
}
else
{
    <h1>@CategoryName Recipes</h1>
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">All Categories</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    var recipes = RecipeService.GetRecipesByCategory(CategoryName);
    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter]
    public string? CategoryName { get; set; }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe Not Found") - RecipeShare</PageTitle>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
    <a href="categories" class="btn btn-primary">Browse Recipes</a>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="categories">All Categories</a></li>
            <li class="breadcrumb-item"><a href="categories/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <h3>Ingredients</h3>
    <ul class="list-group mb-3">
        @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var stepText = System.Text.RegularExpressions.Regex.Replace(step, @"^\d+\.\s*", "");
            <li class="list-group-item">@stepText</li>
        }
    </ol>

    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" RatingCount="recipe.RatingCount" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeShare.Models.Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="card mt-3">
    <div class="card-body">
        <h5 class="card-title">Rate this Recipe</h5>
        <div class="star-rating mb-2">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span class="star @(star <= selectedRating ? "selected" : "")"
                      @onclick="() => Rate(star)"
                      style="cursor: pointer; font-size: 1.5rem;"
                      title="@star star(s)">
                    @(star <= selectedRating ? "★" : "☆")
                </span>
            }
        </div>
        @if (submitted)
        {
            <div class="alert alert-success" role="alert">
                Thanks for rating! You gave @selectedRating star(s).
            </div>
        }
        <p class="text-muted mb-0">
            @if (RatingCount > 0)
            {
                <span>Average: ⭐ @CurrentAverage.ToString("F1") (@RatingCount ratings)</span>
            }
            else
            {
                <span>Be the first to rate this recipe!</span>
            }
        </p>
    </div>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);

        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Recipe Submitted!</h4>
        <p>Your recipe "<strong>@model.Title</strong>" has been added to the <strong>@model.Category</strong> category.</p>
        <hr>
        <a href="recipe/@submittedId" class="btn btn-primary me-2">View Recipe</a>
        <button class="btn btn-outline-secondary" @onclick="ResetForm">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;
    private int submittedId;

    private void HandleSubmit()
    {
        var recipe = new RecipeShare.Models.Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Ingredients = model.Ingredients,
            Steps = model.Steps
        };

        RecipeService.AddRecipe(recipe);
        submittedId = recipe.Id;
        submitted = true;
    }

    private void ResetForm()
    {
        model = new();
        submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
